import { createContext, useContext, useState, useCallback, useEffect } from 'react';
import * as authService from '../services/authService';

const AuthContext = createContext(null);

export const useAuth = () => {
    const ctx = useContext(AuthContext);
    if (!ctx) throw new Error('useAuth must be used within AuthProvider');
    return ctx;
};

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    // Restore session on mount
    useEffect(() => {
        const session = authService.getSession();
        if (session?.user) {
            setUser(session.user);
        }
        setLoading(false);
    }, []);

    const login = useCallback(async (email, password) => {
        const result = authService.login(email, password);
        if (result.success) {
            setUser(result.user);
        }
        return result;
    }, []);

    const register = useCallback(async (userData) => {
        return authService.register(userData);
    }, []);

    const verifyEmail = useCallback(async (userId, code) => {
        return authService.verifyEmail(userId, code);
    }, []);

    const resendVerification = useCallback(async (userId) => {
        return authService.resendVerification(userId);
    }, []);

    const logout = useCallback(() => {
        authService.logout();
        setUser(null);
    }, []);

    const refreshUser = useCallback(() => {
        const session = authService.getSession();
        if (session?.user) {
            setUser(session.user);
        }
    }, []);

    return (
        <AuthContext.Provider value={{
            user,
            loading,
            isAuthenticated: !!user,
            login,
            register,
            verifyEmail,
            resendVerification,
            logout,
            refreshUser,
        }}>
            {children}
        </AuthContext.Provider>
    );
};

import { useState, useCallback, useRef, useEffect } from 'react';
import {
    Inbox, Brain, Target, Database, Sparkles, CheckCircle, Send,
    ChevronRight, Play, RotateCcw, User, MessageCircle,
    ArrowDown, Zap
} from 'lucide-react';
import { useApp } from '../context/AppContext';
import { patients } from '../data/mockData';
import { pipelineStages } from '../data/mockData';

const stageIcons = {
    ingestion: Inbox,
    nlp: Brain,
    intent: Target,
    context: Database,
    generation: Sparkles,
    review: CheckCircle,
    delivery: Send,
};

const stageColors = {
    ingestion: '#6366f1',
    nlp: '#06b6d4',
    intent: '#8b5cf6',
    context: '#3b82f6',
    generation: '#10b981',
    review: '#f59e0b',
    delivery: '#ec4899',
};

export default function AIPipeline() {
    const { sendPatientMessage, processingStages } = useApp();
    const [activeDemo, setActiveDemo] = useState(false);
    const [demoStages, setDemoStages] = useState({});
    const [demoResult, setDemoResult] = useState(null);
    const [demoPatient, setDemoPatient] = useState(patients[0].id);
    const [demoMessage, setDemoMessage] = useState('');
    const [demoChannel, setDemoChannel] = useState('chat');
    const resultRef = useRef(null);

    const presetMessages = [
        { label: 'Symptom Report', text: "My blood sugar has been consistently above 250 mg/dL for the past week. I'm feeling very thirsty and tired. Should I be worried?" },
        { label: 'Med Inquiry', text: "I started taking the new cholesterol medication and I'm experiencing muscle pain. Is this a normal side effect?" },
        { label: 'Appointment', text: "I'd like to reschedule my appointment for next Friday to Monday instead. Is there availability?" },
        { label: 'Prescription', text: "I'm running low on my inhaler, can I get a refill please?" },
        { label: 'Billing', text: "I received a bill for ₹5,000 but my insurance should cover this. Can someone help?" },
    ];

    const runDemoProcessing = useCallback(async () => {
        if (!demoMessage.trim() || activeDemo) return;

        setActiveDemo(true);
        setDemoResult(null);
        setDemoStages({});

        const stageOrder = ['ingestion', 'nlp', 'intent', 'context', 'generation'];
        for (const stage of stageOrder) {
            setDemoStages(prev => ({ ...prev, [stage]: 'processing' }));
            await new Promise(r => setTimeout(r, 800 + Math.random() * 400));
            setDemoStages(prev => ({ ...prev, [stage]: 'complete' }));
        }

        // Use the actual AI service
        const msgId = await sendPatientMessage(demoPatient, demoMessage, demoChannel);
        setDemoResult(msgId);
        setActiveDemo(false);

        setTimeout(() => {
            resultRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }, 300);
    }, [demoMessage, demoPatient, demoChannel, activeDemo, sendPatientMessage]);

    return (
        <div className="page-container">
            <div className="page-header">
                <h1 className="page-title">AI Processing Pipeline</h1>
                <p className="page-subtitle">
                    Visualize the end-to-end AI pipeline from patient message ingestion to response delivery
                </p>
            </div>

            {/* Pipeline Visualization */}
            <div style={{ marginBottom: '2.5rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1.25rem' }}>
                    <Zap size={18} color="var(--color-accent)" />
                    <h2 style={{ fontSize: '1.125rem', fontWeight: 600 }}>Pipeline Architecture</h2>
                </div>

                <div style={{
                    display: 'flex',
                    flexDirection: 'column',
                    gap: '0',
                    position: 'relative',
                }}>
                    {pipelineStages.map((stage, idx) => {
                        const Icon = stageIcons[stage.id] || Brain;
                        const color = stageColors[stage.id] || '#6366f1';
                        const demoStatus = demoStages[stage.id];
                        const isProcessing = demoStatus === 'processing';
                        const isComplete = demoStatus === 'complete';

                        return (
                            <div key={stage.id}>
                                <div
                                    className="animate-fade-in"
                                    style={{
                                        display: 'flex',
                                        alignItems: 'flex-start',
                                        gap: '1.25rem',
                                        padding: '1.25rem 1.5rem',
                                        background: isProcessing ? `${color}10` : isComplete ? `${color}08` : 'var(--color-bg-card)',
                                        border: `1px solid ${isProcessing ? `${color}40` : isComplete ? `${color}25` : 'var(--color-border)'}`,
                                        borderRadius: 'var(--radius-lg)',
                                        transition: 'all var(--transition-base)',
                                        animationDelay: `${idx * 0.08}s`,
                                        position: 'relative',
                                        overflow: 'hidden',
                                    }}
                                >
                                    {/* Processing shimmer */}
                                    {isProcessing && (
                                        <div style={{
                                            position: 'absolute',
                                            inset: 0,
                                            background: `linear-gradient(90deg, transparent, ${color}10, transparent)`,
                                            backgroundSize: '200% 100%',
                                            animation: 'shimmer 1.5s ease-in-out infinite',
                                        }} />
                                    )}

                                    {/* Stage Number + Icon */}
                                    <div style={{
                                        display: 'flex',
                                        flexDirection: 'column',
                                        alignItems: 'center',
                                        gap: '0.25rem',
                                        position: 'relative',
                                        zIndex: 1,
                                    }}>
                                        <div style={{
                                            width: 48,
                                            height: 48,
                                            borderRadius: 'var(--radius-md)',
                                            background: isComplete ? color : `${color}20`,
                                            display: 'flex',
                                            alignItems: 'center',
                                            justifyContent: 'center',
                                            transition: 'all var(--transition-base)',
                                            boxShadow: isProcessing ? `0 0 20px ${color}40` : 'none',
                                        }}>
                                            {isComplete ? (
                                                <CheckCircle size={22} color="white" />
                                            ) : isProcessing ? (
                                                <div className="typing-indicator">
                                                    <span style={{ background: color }} />
                                                    <span style={{ background: color }} />
                                                    <span style={{ background: color }} />
                                                </div>
                                            ) : (
                                                <Icon size={22} color={color} />
                                            )}
                                        </div>
                                        <span style={{
                                            fontSize: '0.625rem',
                                            fontWeight: 700,
                                            color: 'var(--color-text-muted)',
                                            textTransform: 'uppercase',
                                            letterSpacing: '0.05em',
                                        }}>
                                            Step {idx + 1}
                                        </span>
                                    </div>

                                    {/* Stage Content */}
                                    <div style={{ flex: 1, position: 'relative', zIndex: 1 }}>
                                        <div style={{
                                            fontSize: '1rem',
                                            fontWeight: 600,
                                            color: isComplete ? color : 'var(--color-text-primary)',
                                            marginBottom: '0.25rem',
                                        }}>
                                            {stage.label}
                                        </div>
                                        <div style={{
                                            fontSize: '0.8125rem',
                                            color: 'var(--color-text-secondary)',
                                            lineHeight: 1.5,
                                            maxWidth: '600px',
                                        }}>
                                            {stage.description}
                                        </div>
                                    </div>

                                    {/* Metrics */}
                                    <div style={{
                                        display: 'flex',
                                        gap: '1.5rem',
                                        flexShrink: 0,
                                        position: 'relative',
                                        zIndex: 1,
                                    }}>
                                        {Object.entries(stage.metrics).map(([key, val]) => (
                                            <div key={key} style={{ textAlign: 'right' }}>
                                                <div style={{
                                                    fontSize: '0.6875rem',
                                                    color: 'var(--color-text-tertiary)',
                                                    textTransform: 'uppercase',
                                                    letterSpacing: '0.05em',
                                                    marginBottom: '0.125rem',
                                                }}>
                                                    {key}
                                                </div>
                                                <div style={{
                                                    fontSize: '0.9375rem',
                                                    fontWeight: 700,
                                                    color: color,
                                                }}>
                                                    {val}
                                                </div>
                                            </div>
                                        ))}
                                    </div>

                                    {/* Status indicator */}
                                    <div style={{
                                        position: 'absolute',
                                        top: '0.5rem',
                                        right: '0.5rem',
                                        width: 8,
                                        height: 8,
                                        borderRadius: '50%',
                                        background: isComplete ? '#10b981' : isProcessing ? color : '#22c55e',
                                        boxShadow: isProcessing ? `0 0 8px ${color}` : '0 0 4px #22c55e80',
                                    }} />
                                </div>

                                {/* Connector Arrow */}
                                {idx < pipelineStages.length - 1 && (
                                    <div style={{
                                        display: 'flex',
                                        justifyContent: 'center',
                                        padding: '0.25rem 0',
                                    }}>
                                        <ArrowDown size={18} color={demoStages[stage.id] === 'complete' ? stageColors[stage.id] : 'var(--color-text-muted)'} style={{ opacity: 0.5 }} />
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Demo Panel */}
            <div
                className="card-flat"
                style={{ padding: '2rem' }}
            >
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1.25rem' }}>
                    <Play size={18} color="var(--color-primary)" />
                    <h2 style={{ fontSize: '1.125rem', fontWeight: 600 }}>Live Demo — Test the Pipeline</h2>
                </div>
                <p style={{ fontSize: '0.875rem', color: 'var(--color-text-secondary)', marginBottom: '1.5rem' }}>
                    Select a patient, compose a message, and watch the AI pipeline process it in real-time.
                </p>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
                    <div>
                        <label style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--color-text-tertiary)', display: 'block', marginBottom: '0.375rem' }}>
                            Patient
                        </label>
                        <select
                            className="input"
                            id="demo-patient-select"
                            value={demoPatient}
                            onChange={e => setDemoPatient(e.target.value)}
                            disabled={activeDemo}
                        >
                            {patients.map(p => (
                                <option key={p.id} value={p.id}>
                                    {p.name} — {p.conditions.join(', ')}
                                </option>
                            ))}
                        </select>
                    </div>
                    <div>
                        <label style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--color-text-tertiary)', display: 'block', marginBottom: '0.375rem' }}>
                            Channel
                        </label>
                        <select
                            className="input"
                            id="demo-channel-select"
                            value={demoChannel}
                            onChange={e => setDemoChannel(e.target.value)}
                            disabled={activeDemo}
                        >
                            <option value="email">Email</option>
                            <option value="portal">Patient Portal</option>
                            <option value="chat">Live Chat</option>
                        </select>
                    </div>
                </div>

                {/* Preset Messages */}
                <div style={{ marginBottom: '0.75rem' }}>
                    <label style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--color-text-tertiary)', display: 'block', marginBottom: '0.375rem' }}>
                        Quick Presets
                    </label>
                    <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                        {presetMessages.map(pm => (
                            <button
                                key={pm.label}
                                className="btn btn-secondary btn-sm"
                                onClick={() => setDemoMessage(pm.text)}
                                disabled={activeDemo}
                                style={{ fontSize: '0.75rem' }}
                            >
                                {pm.label}
                            </button>
                        ))}
                    </div>
                </div>

                <div>
                    <label style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--color-text-tertiary)', display: 'block', marginBottom: '0.375rem' }}>
                        Patient Message
                    </label>
                    <textarea
                        className="input"
                        id="demo-message-input"
                        rows={4}
                        placeholder="Type a patient message here or select a preset above..."
                        value={demoMessage}
                        onChange={e => setDemoMessage(e.target.value)}
                        disabled={activeDemo}
                        style={{ minHeight: '120px' }}
                    />
                </div>

                <div style={{ display: 'flex', gap: '0.75rem', marginTop: '1rem' }}>
                    <button
                        className="btn btn-primary btn-lg"
                        id="run-pipeline-btn"
                        onClick={runDemoProcessing}
                        disabled={!demoMessage.trim() || activeDemo}
                    >
                        {activeDemo ? (
                            <>
                                <div className="typing-indicator">
                                    <span /><span /><span />
                                </div>
                                Processing...
                            </>
                        ) : (
                            <>
                                <Play size={18} /> Run AI Pipeline
                            </>
                        )}
                    </button>
                    <button
                        className="btn btn-secondary btn-lg"
                        onClick={() => {
                            setDemoMessage('');
                            setDemoResult(null);
                            setDemoStages({});
                        }}
                        disabled={activeDemo}
                    >
                        <RotateCcw size={16} /> Reset
                    </button>
                </div>

                {/* Result */}
                {demoResult && (
                    <div
                        ref={resultRef}
                        className="animate-fade-in-up"
                        style={{
                            marginTop: '1.5rem',
                            padding: '1.25rem',
                            background: 'rgba(16,185,129,0.06)',
                            border: '1px solid rgba(16,185,129,0.2)',
                            borderRadius: 'var(--radius-md)',
                        }}
                    >
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem' }}>
                            <CheckCircle size={18} color="var(--color-success)" />
                            <span style={{ fontWeight: 600, color: 'var(--color-success-light)' }}>Pipeline Complete!</span>
                        </div>
                        <p style={{ fontSize: '0.875rem', color: 'var(--color-text-secondary)' }}>
                            Message has been processed and an AI draft has been generated. You can view it in the{' '}
                            <a href="/messages" style={{ color: 'var(--color-primary-light)', textDecoration: 'none', fontWeight: 500 }}>Messages</a>{' '}
                            or{' '}
                            <a href="/staff-dashboard" style={{ color: 'var(--color-primary-light)', textDecoration: 'none', fontWeight: 500 }}>Staff Dashboard</a>.
                        </p>
                    </div>
                )}
            </div>
        </div>
    );
}

import { useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    MessageSquare, Brain, CheckCircle, Clock, AlertTriangle,
    TrendingUp, Users, Star, Activity, ArrowUpRight,
    Mail, Globe, MessageCircle, Zap, Shield
} from 'lucide-react';
import { useApp } from '../context/AppContext';
import { dashboardStats, messageVolumeData, intentDistributionData } from '../data/mockData';
import {
    BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer,
    PieChart, Pie, Cell, AreaChart, Area, CartesianGrid
} from 'recharts';

const StatCard = ({ icon: Icon, label, value, sublabel, color, trend, onClick }) => (
    <div
        className="card"
        onClick={onClick}
        style={{
            cursor: onClick ? 'pointer' : 'default',
            display: 'flex',
            flexDirection: 'column',
            gap: '0.75rem',
        }}
    >
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <div
                style={{
                    width: 44,
                    height: 44,
                    borderRadius: 'var(--radius-md)',
                    background: `${color}15`,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                }}
            >
                <Icon size={22} color={color} />
            </div>
            {trend && (
                <div style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.25rem',
                    fontSize: '0.75rem',
                    fontWeight: 600,
                    color: trend > 0 ? 'var(--color-success)' : 'var(--color-danger)',
                }}>
                    <TrendingUp size={14} style={{ transform: trend < 0 ? 'rotate(180deg)' : 'none' }} />
                    {Math.abs(trend)}%
                </div>
            )}
        </div>
        <div>
            <div style={{ fontSize: '1.75rem', fontWeight: 800, lineHeight: 1.1 }}>{value}</div>
            <div style={{ fontSize: '0.8125rem', color: 'var(--color-text-secondary)', marginTop: '0.125rem' }}>{label}</div>
        </div>
        {sublabel && (
            <div style={{ fontSize: '0.75rem', color: 'var(--color-text-tertiary)' }}>{sublabel}</div>
        )}
    </div>
);

const ChannelIcon = ({ channel }) => {
    const icons = { email: Mail, portal: Globe, chat: MessageCircle };
    const Icon = icons[channel] || MessageCircle;
    return <Icon size={14} />;
};

const priorityColors = {
    critical: '#ef4444',
    high: '#f59e0b',
    medium: '#3b82f6',
    low: '#10b981',
};

const CustomTooltip = ({ active, payload, label }) => {
    if (!active || !payload?.length) return null;
    return (
        <div style={{
            background: 'var(--color-bg-elevated)',
            border: '1px solid var(--color-border)',
            borderRadius: 'var(--radius-md)',
            padding: '0.75rem',
            fontSize: '0.75rem',
        }}>
            <div style={{ fontWeight: 600, marginBottom: '0.375rem' }}>{label}</div>
            {payload.map((p, i) => (
                <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginTop: '0.25rem' }}>
                    <span style={{ width: 8, height: 8, borderRadius: '50%', background: p.color, display: 'inline-block' }} />
                    <span style={{ color: 'var(--color-text-secondary)' }}>{p.name}: </span>
                    <span style={{ fontWeight: 600 }}>{p.value}</span>
                </div>
            ))}
        </div>
    );
};

export default function Dashboard() {
    const { messages, activityLog, getPatient } = useApp();
    const navigate = useNavigate();

    const pendingMessages = useMemo(() =>
        messages.filter(m => m.status === 'pending_review').sort((a, b) =>
            new Date(b.timestamp) - new Date(a.timestamp)
        ).slice(0, 5),
        [messages]
    );

    const recentActivity = useMemo(() => activityLog.slice(0, 8), [activityLog]);

    const formatTime = (ts) => {
        const d = new Date(ts);
        const now = new Date();
        const diff = (now - d) / 1000 / 60;
        if (diff < 1) return 'Just now';
        if (diff < 60) return `${Math.floor(diff)}m ago`;
        if (diff < 1440) return `${Math.floor(diff / 60)}h ago`;
        return d.toLocaleDateString();
    };

    return (
        <div className="page-container">
            {/* Header */}
            <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div>
                    <h1 className="page-title">Dashboard</h1>
                    <p className="page-subtitle">Real-time overview of your AI-powered communication platform</p>
                </div>
                <button className="btn btn-primary" onClick={() => navigate('/messages')}>
                    <MessageSquare size={16} /> View Messages
                </button>
            </div>

            {/* Stat Cards */}
            <div
                className="stagger-children"
                style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
                    gap: '1rem',
                    marginBottom: '1.5rem',
                }}
            >
                <StatCard
                    icon={MessageSquare}
                    label="Total Messages"
                    value={dashboardStats.totalMessages}
                    sublabel={`${dashboardStats.processedToday} processed today`}
                    color="#6366f1"
                    trend={12}
                />
                <StatCard
                    icon={Brain}
                    label="AI Accuracy"
                    value={`${dashboardStats.aiAccuracy}%`}
                    sublabel="Last 30 days"
                    color="#06b6d4"
                    trend={2.3}
                />
                <StatCard
                    icon={Clock}
                    label="Avg Response Time"
                    value={dashboardStats.avgResponseTime}
                    sublabel="AI draft generation"
                    color="#8b5cf6"
                    trend={-15}
                />
                <StatCard
                    icon={CheckCircle}
                    label="Approved Today"
                    value={dashboardStats.approvedToday}
                    sublabel={`${dashboardStats.pendingReview} pending review`}
                    color="#10b981"
                    trend={8}
                    onClick={() => navigate('/staff-dashboard')}
                />
            </div>

            {/* Charts Row */}
            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1.5rem', marginBottom: '1.5rem' }}>
                {/* Message Volume Chart */}
                <div className="card-flat" style={{ padding: '1.5rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                        <div>
                            <h3 style={{ fontSize: '1rem', fontWeight: 600 }}>Message Volume</h3>
                            <p style={{ fontSize: '0.8125rem', color: 'var(--color-text-tertiary)', marginTop: '0.125rem' }}>
                                Incoming messages by channel this week
                            </p>
                        </div>
                        <div className="badge badge-accent">
                            <Activity size={12} /> This Week
                        </div>
                    </div>
                    <ResponsiveContainer width="100%" height={240}>
                        <BarChart data={messageVolumeData} barGap={4}>
                            <CartesianGrid strokeDasharray="3 3" stroke="rgba(99,102,241,0.06)" />
                            <XAxis dataKey="day" stroke="var(--color-text-muted)" fontSize={12} tickLine={false} axisLine={false} />
                            <YAxis stroke="var(--color-text-muted)" fontSize={12} tickLine={false} axisLine={false} />
                            <Tooltip content={<CustomTooltip />} />
                            <Bar dataKey="email" name="Email" fill="#6366f1" radius={[4, 4, 0, 0]} />
                            <Bar dataKey="portal" name="Portal" fill="#06b6d4" radius={[4, 4, 0, 0]} />
                            <Bar dataKey="chat" name="Chat" fill="#8b5cf6" radius={[4, 4, 0, 0]} />
                        </BarChart>
                    </ResponsiveContainer>
                </div>

                {/* Intent Distribution */}
                <div className="card-flat" style={{ padding: '1.5rem' }}>
                    <div style={{ marginBottom: '1rem' }}>
                        <h3 style={{ fontSize: '1rem', fontWeight: 600 }}>Intent Distribution</h3>
                        <p style={{ fontSize: '0.8125rem', color: 'var(--color-text-tertiary)', marginTop: '0.125rem' }}>
                            AI-classified categories
                        </p>
                    </div>
                    <ResponsiveContainer width="100%" height={180}>
                        <PieChart>
                            <Pie
                                data={intentDistributionData}
                                cx="50%"
                                cy="50%"
                                innerRadius={50}
                                outerRadius={75}
                                paddingAngle={3}
                                dataKey="value"
                            >
                                {intentDistributionData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.color} />
                                ))}
                            </Pie>
                            <Tooltip content={<CustomTooltip />} />
                        </PieChart>
                    </ResponsiveContainer>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem', marginTop: '0.5rem' }}>
                        {intentDistributionData.slice(0, 4).map(item => (
                            <div key={item.name} style={{ display: 'flex', alignItems: 'center', gap: '0.375rem', fontSize: '0.75rem' }}>
                                <span style={{ width: 8, height: 8, borderRadius: '50%', background: item.color, display: 'inline-block' }} />
                                <span style={{ color: 'var(--color-text-secondary)' }}>{item.name}</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* Bottom Row: Pending Messages + Activity Log */}
            <div style={{ display: 'grid', gridTemplateColumns: '1.3fr 1fr', gap: '1.5rem' }}>
                {/* Pending Messages */}
                <div className="card-flat" style={{ padding: '1.5rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                        <h3 style={{ fontSize: '1rem', fontWeight: 600 }}>
                            <AlertTriangle size={16} color="var(--color-warning)" style={{ verticalAlign: -2, marginRight: 6 }} />
                            Pending Review
                        </h3>
                        <button className="btn btn-ghost btn-sm" onClick={() => navigate('/staff-dashboard')}>
                            View All <ArrowUpRight size={14} />
                        </button>
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                        {pendingMessages.map(msg => {
                            const patient = getPatient(msg.patientId);
                            return (
                                <div
                                    key={msg.id}
                                    onClick={() => navigate('/staff-dashboard')}
                                    style={{
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '0.875rem',
                                        padding: '0.75rem',
                                        background: 'var(--color-bg-tertiary)',
                                        borderRadius: 'var(--radius-md)',
                                        cursor: 'pointer',
                                        transition: 'all var(--transition-fast)',
                                        borderLeft: `3px solid ${priorityColors[msg.priority] || '#6366f1'}`,
                                    }}
                                    onMouseEnter={e => e.currentTarget.style.background = 'var(--color-bg-card-hover)'}
                                    onMouseLeave={e => e.currentTarget.style.background = 'var(--color-bg-tertiary)'}
                                >
                                    <div
                                        style={{
                                            width: 36,
                                            height: 36,
                                            borderRadius: '50%',
                                            background: `${priorityColors[msg.priority]}15`,
                                            display: 'flex',
                                            alignItems: 'center',
                                            justifyContent: 'center',
                                            color: priorityColors[msg.priority],
                                            flexShrink: 0,
                                        }}
                                    >
                                        <ChannelIcon channel={msg.channel} />
                                    </div>
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <div style={{ fontSize: '0.8125rem', fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                            {patient?.name || 'Unknown'}
                                        </div>
                                        <div style={{ fontSize: '0.75rem', color: 'var(--color-text-tertiary)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                            {msg.subject}
                                        </div>
                                    </div>
                                    <div style={{ textAlign: 'right', flexShrink: 0 }}>
                                        <span className={`badge badge-${msg.priority === 'critical' ? 'danger' : msg.priority === 'high' ? 'warning' : 'info'}`}>
                                            {msg.priority}
                                        </span>
                                        <div style={{ fontSize: '0.6875rem', color: 'var(--color-text-muted)', marginTop: '0.25rem' }}>
                                            {formatTime(msg.timestamp)}
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Activity Log */}
                <div className="card-flat" style={{ padding: '1.5rem' }}>
                    <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '1rem' }}>
                        <Zap size={16} color="var(--color-accent)" style={{ verticalAlign: -2, marginRight: 6 }} />
                        Recent Activity
                    </h3>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.125rem' }}>
                        {recentActivity.map((item, idx) => (
                            <div
                                key={item.id}
                                style={{
                                    display: 'flex',
                                    gap: '0.75rem',
                                    padding: '0.625rem 0',
                                    borderBottom: idx < recentActivity.length - 1 ? '1px solid var(--color-border-light)' : 'none',
                                    alignItems: 'flex-start',
                                }}
                            >
                                <div
                                    style={{
                                        width: 28,
                                        height: 28,
                                        borderRadius: '50%',
                                        background: item.type === 'approved' ? 'rgba(16,185,129,0.12)' :
                                            item.type === 'ai_processed' ? 'rgba(6,182,212,0.12)' :
                                                'rgba(99,102,241,0.12)',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center',
                                        flexShrink: 0,
                                        marginTop: '0.125rem',
                                    }}
                                >
                                    {item.type === 'approved' ? <CheckCircle size={13} color="#10b981" /> :
                                        item.type === 'ai_processed' ? <Brain size={13} color="#06b6d4" /> :
                                            <Mail size={13} color="#6366f1" />}
                                </div>
                                <div style={{ flex: 1, minWidth: 0 }}>
                                    <div style={{
                                        fontSize: '0.8125rem',
                                        color: 'var(--color-text-secondary)',
                                        lineHeight: 1.4,
                                        overflow: 'hidden',
                                        textOverflow: 'ellipsis',
                                        display: '-webkit-box',
                                        WebkitLineClamp: 2,
                                        WebkitBoxOrient: 'vertical',
                                    }}>
                                        {item.description}
                                    </div>
                                    <div style={{ fontSize: '0.6875rem', color: 'var(--color-text-muted)', marginTop: '0.125rem' }}>
                                        {formatTime(item.timestamp)}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Mail, Lock, Eye, EyeOff, ArrowRight, Zap, Shield, Activity, Users } from 'lucide-react';

export default function Login() {
    const { login } = useAuth();
    const navigate = useNavigate();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        if (!email || !password) { setError('Please fill in all fields'); return; }

        setLoading(true);
        const result = await login(email, password);
        setLoading(false);

        if (result.success) {
            if (result.user.role === 'doctor') navigate('/doctor');
            else if (result.user.role === 'nurse') navigate('/nurse');
            else navigate('/patient');
        } else {
            if (result.needsVerification) navigate(`/verify/${result.userId}`);
            else setError(result.error);
        }
    };

    const fillDemo = (role) => {
        const creds = {
            doctor: { email: 'doctor@tetherx.com', password: 'doctor123' },
            nurse: { email: 'nurse@tetherx.com', password: 'nurse123' },
            patient: { email: 'patient@tetherx.com', password: 'patient123' },
        };
        setEmail(creds[role].email);
        setPassword(creds[role].password);
        setError('');
    };

    return (
        <div style={{ display: 'flex', minHeight: '100vh' }}>

            {/* ─── LEFT PANEL — Dark branding ─────────────────────────── */}
            <div style={{
                width: '50%',
                background: 'linear-gradient(160deg, #0a2e2e 0%, #0f3d3d 40%, #0a2e2e 100%)',
                position: 'relative',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'space-between',
                padding: '2.5rem',
                overflow: 'hidden',
                color: 'white',
            }}>
                {/* Decorative animated nodes */}
                <svg style={{
                    position: 'absolute', inset: 0, width: '100%', height: '100%',
                    opacity: 0.12, pointerEvents: 'none',
                }}>
                    <defs>
                        <radialGradient id="nodeGlow" cx="50%" cy="50%" r="50%">
                            <stop offset="0%" stopColor="#10b981" stopOpacity="0.8" />
                            <stop offset="100%" stopColor="#10b981" stopOpacity="0" />
                        </radialGradient>
                    </defs>
                    {/* DNA helix pattern */}
                    {Array.from({ length: 18 }).map((_, i) => {
                        const y = 50 + i * 50;
                        const x1 = 200 + Math.sin(i * 0.5) * 120;
                        const x2 = 200 - Math.sin(i * 0.5) * 120;
                        return (
                            <g key={i}>
                                <circle cx={x1} cy={y} r={4} fill="#10b981" opacity={0.4 + Math.random() * 0.4}>
                                    <animate attributeName="opacity" values={`${0.3};${0.8};${0.3}`} dur={`${2 + Math.random() * 2}s`} repeatCount="indefinite" />
                                </circle>
                                <circle cx={x2} cy={y} r={3} fill="#14b8a6" opacity={0.3 + Math.random() * 0.3}>
                                    <animate attributeName="opacity" values={`${0.2};${0.7};${0.2}`} dur={`${2.5 + Math.random() * 2}s`} repeatCount="indefinite" />
                                </circle>
                                <line x1={x1} y1={y} x2={x2} y2={y} stroke="#10b981" strokeWidth="0.5" opacity="0.3" />
                                {i < 17 && (
                                    <>
                                        <line x1={x1} y1={y} x2={200 + Math.sin((i + 1) * 0.5) * 120} y2={y + 50} stroke="#10b981" strokeWidth="0.5" opacity="0.2" />
                                        <line x1={x2} y1={y} x2={200 - Math.sin((i + 1) * 0.5) * 120} y2={y + 50} stroke="#14b8a6" strokeWidth="0.5" opacity="0.15" />
                                    </>
                                )}
                            </g>
                        );
                    })}
                    {/* Scattered outer dots */}
                    {Array.from({ length: 25 }).map((_, i) => (
                        <circle key={`dot-${i}`} cx={40 + Math.random() * 350} cy={30 + Math.random() * 900} r={1.5 + Math.random() * 2} fill="#10b981" opacity={0.15 + Math.random() * 0.25}>
                            <animate attributeName="opacity" values={`${0.1};${0.4};${0.1}`} dur={`${3 + Math.random() * 3}s`} repeatCount="indefinite" />
                        </circle>
                    ))}
                </svg>

                {/* Logo */}
                <div style={{ position: 'relative', zIndex: 2 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <div style={{
                            width: 42, height: 42, borderRadius: 'var(--radius-md)',
                            background: 'rgba(16,185,129,0.2)', border: '1px solid rgba(16,185,129,0.3)',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                        }}>
                            <Zap size={22} color="#10b981" />
                        </div>
                        <div>
                            <div style={{ fontWeight: 700, fontSize: '1.125rem', letterSpacing: '-0.01em' }}>TetherX Health</div>
                            <div style={{ fontSize: '0.6875rem', color: '#10b981', fontWeight: 400, letterSpacing: '0.02em' }}>Healthcare Intelligence Platform</div>
                        </div>
                    </div>
                </div>

                {/* Tagline */}
                <div style={{ position: 'relative', zIndex: 2 }}>
                    <h1 style={{
                        fontSize: '3rem', fontWeight: 700, lineHeight: 1.15,
                        letterSpacing: '-0.02em',
                    }}>
                        Operational<br />
                        Intelligence,<br />
                        <span style={{ color: '#10b981' }}>Reimagined.</span>
                    </h1>
                    <p style={{
                        marginTop: '1.25rem', fontSize: '1rem', color: 'rgba(255,255,255,0.6)',
                        lineHeight: 1.7, maxWidth: 380,
                    }}>
                        Real-time analytics, predictive insights, and AI-powered
                        decision support for modern healthcare administration.
                    </p>
                </div>

                {/* Stats */}
                <div style={{ position: 'relative', zIndex: 2, display: 'flex', gap: '2.5rem' }}>
                    {[
                        { value: '847+', label: 'Active Cases' },
                        { value: '218', label: 'Staff Monitored' },
                        { value: '94%', label: 'SLA Compliance' },
                    ].map(stat => (
                        <div key={stat.label}>
                            <div style={{ fontSize: '1.75rem', fontWeight: 700 }}>{stat.value}</div>
                            <div style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.45)', marginTop: '0.125rem' }}>{stat.label}</div>
                        </div>
                    ))}
                </div>
            </div>

            {/* ─── RIGHT PANEL — Login form ──────────────────────────── */}
            <div style={{
                width: '50%',
                background: '#ffffff',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                padding: '3rem 4rem',
            }}>
                <div className="animate-fade-in" style={{ maxWidth: 420, width: '100%', margin: '0 auto' }}>
                    <h2 style={{ fontSize: '1.875rem', fontWeight: 700, color: '#111827', marginBottom: '0.375rem' }}>
                        Welcome back
                    </h2>
                    <p style={{ fontSize: '0.9375rem', color: '#6b7280', marginBottom: '2rem' }}>
                        Sign in to access the command center
                    </p>

                    {/* Error */}
                    {error && (
                        <div style={{
                            padding: '0.75rem 1rem', marginBottom: '1.25rem',
                            background: '#fef2f2', border: '1px solid #fecaca',
                            borderRadius: 'var(--radius-md)', color: '#dc2626',
                            fontSize: '0.8125rem', fontWeight: 500,
                        }}>
                            {error}
                        </div>
                    )}

                    <form onSubmit={handleSubmit}>
                        {/* Email */}
                        <div style={{ marginBottom: '1.25rem' }}>
                            <label style={{
                                display: 'block', marginBottom: '0.5rem',
                                fontSize: '0.75rem', fontWeight: 600,
                                color: '#374151', textTransform: 'uppercase', letterSpacing: '0.05em',
                            }}>
                                Email
                            </label>
                            <input
                                id="login-email"
                                type="email"
                                value={email}
                                onChange={e => setEmail(e.target.value)}
                                placeholder="you@hospital.ai"
                                style={{
                                    width: '100%', padding: '0.75rem 1rem',
                                    border: '1px solid #d1d5db', borderRadius: 'var(--radius-md)',
                                    fontSize: '0.9375rem', color: '#111827',
                                    background: '#ffffff', outline: 'none',
                                    transition: 'border-color 0.2s, box-shadow 0.2s',
                                    fontFamily: 'var(--font-sans)',
                                }}
                                onFocus={e => { e.target.style.borderColor = '#059669'; e.target.style.boxShadow = '0 0 0 3px rgba(5,150,105,0.1)'; }}
                                onBlur={e => { e.target.style.borderColor = '#d1d5db'; e.target.style.boxShadow = 'none'; }}
                            />
                        </div>

                        {/* Password */}
                        <div style={{ marginBottom: '1.75rem' }}>
                            <label style={{
                                display: 'block', marginBottom: '0.5rem',
                                fontSize: '0.75rem', fontWeight: 600,
                                color: '#374151', textTransform: 'uppercase', letterSpacing: '0.05em',
                            }}>
                                Password
                            </label>
                            <div style={{ position: 'relative' }}>
                                <input
                                    id="login-password"
                                    type={showPassword ? 'text' : 'password'}
                                    value={password}
                                    onChange={e => setPassword(e.target.value)}
                                    placeholder="Enter your password"
                                    style={{
                                        width: '100%', padding: '0.75rem 1rem',
                                        paddingRight: '2.75rem',
                                        border: '1px solid #d1d5db', borderRadius: 'var(--radius-md)',
                                        fontSize: '0.9375rem', color: '#111827',
                                        background: '#ffffff', outline: 'none',
                                        transition: 'border-color 0.2s, box-shadow 0.2s',
                                        fontFamily: 'var(--font-sans)',
                                    }}
                                    onFocus={e => { e.target.style.borderColor = '#059669'; e.target.style.boxShadow = '0 0 0 3px rgba(5,150,105,0.1)'; }}
                                    onBlur={e => { e.target.style.borderColor = '#d1d5db'; e.target.style.boxShadow = 'none'; }}
                                />
                                <button
                                    type="button"
                                    onClick={() => setShowPassword(!showPassword)}
                                    style={{
                                        position: 'absolute', right: 10, top: '50%',
                                        transform: 'translateY(-50%)',
                                        background: 'none', border: 'none', cursor: 'pointer',
                                        color: '#9ca3af', padding: 4,
                                    }}
                                >
                                    {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                </button>
                            </div>
                        </div>

                        {/* Submit */}
                        <button
                            type="submit"
                            disabled={loading}
                            style={{
                                width: '100%', padding: '0.8125rem',
                                background: '#059669', color: 'white',
                                border: 'none', borderRadius: 'var(--radius-full)',
                                fontSize: '0.9375rem', fontWeight: 600,
                                cursor: loading ? 'not-allowed' : 'pointer',
                                opacity: loading ? 0.7 : 1,
                                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem',
                                fontFamily: 'var(--font-sans)',
                                transition: 'background 0.2s, box-shadow 0.2s',
                                boxShadow: '0 2px 8px rgba(5,150,105,0.25)',
                            }}
                            onMouseEnter={e => { if (!loading) { e.target.style.background = '#047857'; e.target.style.boxShadow = '0 4px 16px rgba(5,150,105,0.35)'; } }}
                            onMouseLeave={e => { e.target.style.background = '#059669'; e.target.style.boxShadow = '0 2px 8px rgba(5,150,105,0.25)'; }}
                        >
                            {loading ? 'Signing in...' : <>Sign In <ArrowRight size={18} /></>}
                        </button>
                    </form>

                    {/* Create Account */}
                    <div style={{ textAlign: 'center', marginTop: '1.25rem' }}>
                        <span style={{ fontSize: '0.8125rem', color: '#6b7280' }}>
                            New user?{' '}
                            <Link to="/register" style={{ color: '#059669', textDecoration: 'none', fontWeight: 600 }}>
                                Create Account
                            </Link>
                        </span>
                    </div>

                    {/* Demo Credentials */}
                    <div style={{
                        marginTop: '2rem', padding: '1.125rem 1.25rem',
                        background: '#ecfdf5', borderRadius: 'var(--radius-lg)',
                        border: '1px solid #a7f3d0',
                    }}>
                        <div style={{
                            display: 'flex', alignItems: 'center', gap: '0.5rem',
                            marginBottom: '0.75rem',
                        }}>
                            <Shield size={16} color="#059669" />
                            <span style={{ fontSize: '0.8125rem', fontWeight: 700, color: '#065f46' }}>
                                Demo Credentials
                            </span>
                        </div>

                        {[
                            { role: 'Doctor', email: 'doctor@tetherx.com', pw: 'doctor123', dot: '#059669' },
                            { role: 'Nurse', email: 'nurse@tetherx.com', pw: 'nurse123', dot: '#0d9488' },
                            { role: 'Patient', email: 'patient@tetherx.com', pw: 'patient123', dot: '#f59e0b' },
                        ].map(item => (
                            <button
                                key={item.role}
                                type="button"
                                onClick={() => fillDemo(item.role.toLowerCase())}
                                style={{
                                    display: 'flex', alignItems: 'center', gap: '0.5rem',
                                    width: '100%', textAlign: 'left',
                                    background: 'none', border: 'none', cursor: 'pointer',
                                    padding: '0.3125rem 0', fontFamily: 'var(--font-mono)',
                                    fontSize: '0.75rem', color: '#065f46',
                                    transition: 'opacity 0.15s',
                                }}
                                onMouseEnter={e => e.target.style.opacity = '0.7'}
                                onMouseLeave={e => e.target.style.opacity = '1'}
                            >
                                <span style={{
                                    width: 8, height: 8, borderRadius: '50%',
                                    background: item.dot, flexShrink: 0,
                                }} />
                                <span style={{ fontWeight: 600, minWidth: 52 }}>{item.role}:</span>
                                <span>{item.email}</span>
                                <span style={{ color: '#6b7280' }}>/</span>
                                <span>{item.pw}</span>
                            </button>
                        ))}
                    </div>

                    {/* Footer */}
                    <div style={{
                        textAlign: 'center', marginTop: '2rem',
                        fontSize: '0.75rem', color: '#9ca3af',
                    }}>
                        © 2026 TetherX Health — Healthcare Intelligence Platform
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useMemo } from 'react';
import {
    Mail, Globe, MessageCircle, Search, Filter, Send,
    Clock, AlertTriangle, CheckCircle, ChevronDown, User,
    Activity, ArrowRight, Brain, Eye
} from 'lucide-react';
import { useApp } from '../context/AppContext';
import { patients, channels, intentCategories } from '../data/mockData';

const channelIcons = { email: Mail, portal: Globe, chat: MessageCircle };
const priorityColors = {
    critical: { bg: 'rgba(239,68,68,0.12)', color: '#f87171', border: 'rgba(239,68,68,0.3)' },
    high: { bg: 'rgba(245,158,11,0.12)', color: '#fbbf24', border: 'rgba(245,158,11,0.3)' },
    medium: { bg: 'rgba(59,130,246,0.12)', color: '#60a5fa', border: 'rgba(59,130,246,0.3)' },
    low: { bg: 'rgba(16,185,129,0.12)', color: '#34d399', border: 'rgba(16,185,129,0.3)' },
};
const statusLabels = {
    pending_review: 'Pending Review',
    ai_processing: 'AI Processing',
    approved: 'Approved',
    rejected: 'Rejected',
    error: 'Error',
};

export default function Messages() {
    const { messages, getPatient, setSelectedMessageId } = useApp();
    const [searchTerm, setSearchTerm] = useState('');
    const [channelFilter, setChannelFilter] = useState('all');
    const [priorityFilter, setPriorityFilter] = useState('all');
    const [statusFilter, setStatusFilter] = useState('all');
    const [selectedMsg, setSelectedMsg] = useState(null);

    const filteredMessages = useMemo(() => {
        return messages.filter(msg => {
            const patient = getPatient(msg.patientId);
            const matchesSearch = searchTerm === '' ||
                patient?.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                msg.subject.toLowerCase().includes(searchTerm.toLowerCase()) ||
                msg.body.toLowerCase().includes(searchTerm.toLowerCase());
            const matchesChannel = channelFilter === 'all' || msg.channel === channelFilter;
            const matchesPriority = priorityFilter === 'all' || msg.priority === priorityFilter;
            const matchesStatus = statusFilter === 'all' || msg.status === statusFilter;
            return matchesSearch && matchesChannel && matchesPriority && matchesStatus;
        }).sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
    }, [messages, searchTerm, channelFilter, priorityFilter, statusFilter, getPatient]);

    const formatTime = (ts) => {
        const d = new Date(ts);
        return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true }) +
            ' · ' + d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    };

    const selected = selectedMsg || filteredMessages[0];
    const selectedPatient = selected ? getPatient(selected.patientId) : null;

    return (
        <div className="page-container" style={{ padding: '0', height: 'calc(100vh - 64px)', display: 'flex', flexDirection: 'column' }}>
            {/* Header Bar */}
            <div style={{
                padding: '1.25rem 2rem',
                borderBottom: '1px solid var(--color-border-light)',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
            }}>
                <div>
                    <h1 className="page-title" style={{ fontSize: '1.375rem' }}>Messages</h1>
                    <p style={{ fontSize: '0.8125rem', color: 'var(--color-text-tertiary)', marginTop: '0.125rem' }}>
                        {filteredMessages.length} messages · {messages.filter(m => m.status === 'pending_review').length} pending review
                    </p>
                </div>
            </div>

            <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
                {/* Message List Sidebar */}
                <div style={{
                    width: '420px',
                    minWidth: '420px',
                    borderRight: '1px solid var(--color-border-light)',
                    display: 'flex',
                    flexDirection: 'column',
                    background: 'var(--color-bg-secondary)',
                }}>
                    {/* Filters */}
                    <div style={{ padding: '1rem', borderBottom: '1px solid var(--color-border-light)' }}>
                        <div style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: '0.5rem',
                            background: 'var(--color-bg-tertiary)',
                            border: '1px solid var(--color-border)',
                            borderRadius: 'var(--radius-md)',
                            padding: '0.5rem 0.75rem',
                            marginBottom: '0.75rem',
                        }}>
                            <Search size={14} color="var(--color-text-tertiary)" />
                            <input
                                id="message-search"
                                type="text"
                                placeholder="Search messages..."
                                value={searchTerm}
                                onChange={e => setSearchTerm(e.target.value)}
                                style={{
                                    background: 'transparent',
                                    border: 'none',
                                    outline: 'none',
                                    color: 'var(--color-text-primary)',
                                    fontSize: '0.8125rem',
                                    width: '100%',
                                    fontFamily: 'var(--font-sans)',
                                }}
                            />
                        </div>
                        <div style={{ display: 'flex', gap: '0.5rem' }}>
                            <select
                                className="input"
                                style={{ padding: '0.375rem 0.5rem', fontSize: '0.75rem', flex: 1 }}
                                value={channelFilter}
                                onChange={e => setChannelFilter(e.target.value)}
                            >
                                <option value="all">All Channels</option>
                                {channels.map(ch => (
                                    <option key={ch.id} value={ch.id}>{ch.label}</option>
                                ))}
                            </select>
                            <select
                                className="input"
                                style={{ padding: '0.375rem 0.5rem', fontSize: '0.75rem', flex: 1 }}
                                value={priorityFilter}
                                onChange={e => setPriorityFilter(e.target.value)}
                            >
                                <option value="all">All Priority</option>
                                <option value="critical">Critical</option>
                                <option value="high">High</option>
                                <option value="medium">Medium</option>
                                <option value="low">Low</option>
                            </select>
                            <select
                                className="input"
                                style={{ padding: '0.375rem 0.5rem', fontSize: '0.75rem', flex: 1 }}
                                value={statusFilter}
                                onChange={e => setStatusFilter(e.target.value)}
                            >
                                <option value="all">All Status</option>
                                <option value="pending_review">Pending</option>
                                <option value="approved">Approved</option>
                                <option value="rejected">Rejected</option>
                            </select>
                        </div>
                    </div>

                    {/* Message List */}
                    <div style={{ flex: 1, overflowY: 'auto' }}>
                        {filteredMessages.map(msg => {
                            const patient = getPatient(msg.patientId);
                            const ChannelIcon = channelIcons[msg.channel] || MessageCircle;
                            const isSelected = selected?.id === msg.id;
                            const pColor = priorityColors[msg.priority] || priorityColors.medium;

                            return (
                                <div
                                    key={msg.id}
                                    id={`message-${msg.id}`}
                                    onClick={() => setSelectedMsg(msg)}
                                    style={{
                                        padding: '1rem 1.25rem',
                                        borderBottom: '1px solid var(--color-border-light)',
                                        cursor: 'pointer',
                                        background: isSelected ? 'rgba(99,102,241,0.08)' : 'transparent',
                                        borderLeft: isSelected ? '3px solid var(--color-primary)' : '3px solid transparent',
                                        transition: 'all var(--transition-fast)',
                                    }}
                                    onMouseEnter={e => { if (!isSelected) e.currentTarget.style.background = 'rgba(99,102,241,0.04)'; }}
                                    onMouseLeave={e => { if (!isSelected) e.currentTarget.style.background = 'transparent'; }}
                                >
                                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: '0.75rem' }}>
                                        <div style={{
                                            width: 40,
                                            height: 40,
                                            borderRadius: '50%',
                                            background: 'var(--gradient-primary)',
                                            display: 'flex',
                                            alignItems: 'center',
                                            justifyContent: 'center',
                                            flexShrink: 0,
                                            fontSize: '0.875rem',
                                            fontWeight: 700,
                                            color: 'white',
                                        }}>
                                            {patient?.name?.charAt(0) || '?'}
                                        </div>
                                        <div style={{ flex: 1, minWidth: 0 }}>
                                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                                <span style={{ fontWeight: 600, fontSize: '0.875rem' }}>{patient?.name}</span>
                                                <span style={{ fontSize: '0.6875rem', color: 'var(--color-text-muted)' }}>
                                                    {formatTime(msg.timestamp)}
                                                </span>
                                            </div>
                                            <div style={{
                                                fontSize: '0.8125rem',
                                                fontWeight: 500,
                                                marginTop: '0.125rem',
                                                overflow: 'hidden',
                                                textOverflow: 'ellipsis',
                                                whiteSpace: 'nowrap',
                                            }}>
                                                {msg.subject}
                                            </div>
                                            <div style={{
                                                fontSize: '0.75rem',
                                                color: 'var(--color-text-tertiary)',
                                                marginTop: '0.25rem',
                                                overflow: 'hidden',
                                                textOverflow: 'ellipsis',
                                                whiteSpace: 'nowrap',
                                            }}>
                                                {msg.body.slice(0, 80)}...
                                            </div>
                                            <div style={{ display: 'flex', gap: '0.375rem', marginTop: '0.5rem', alignItems: 'center' }}>
                                                <span
                                                    className="badge"
                                                    style={{
                                                        background: pColor.bg,
                                                        color: pColor.color,
                                                        fontSize: '0.625rem',
                                                        padding: '0.125rem 0.5rem',
                                                    }}
                                                >
                                                    {msg.priority}
                                                </span>
                                                <span style={{ display: 'flex', alignItems: 'center', gap: '0.25rem', fontSize: '0.6875rem', color: 'var(--color-text-tertiary)' }}>
                                                    <ChannelIcon size={11} /> {msg.channel}
                                                </span>
                                                {msg.aiClassification && (
                                                    <span style={{ display: 'flex', alignItems: 'center', gap: '0.25rem', fontSize: '0.6875rem', color: 'var(--color-accent)' }}>
                                                        <Brain size={11} /> {Math.round(msg.aiClassification.confidence * 100)}%
                                                    </span>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                        {filteredMessages.length === 0 && (
                            <div className="empty-state" style={{ padding: '3rem' }}>
                                <Mail size={40} color="var(--color-text-muted)" />
                                <p style={{ marginTop: '0.75rem', fontSize: '0.875rem' }}>No messages match your filters</p>
                            </div>
                        )}
                    </div>
                </div>

                {/* Message Detail Panel */}
                {selected ? (
                    <div style={{ flex: 1, overflowY: 'auto', padding: '1.5rem 2rem' }} className="animate-fade-in">
                        {/* Patient Header */}
                        <div style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: '1rem',
                            marginBottom: '1.5rem',
                            padding: '1.25rem',
                            background: 'var(--color-bg-card)',
                            borderRadius: 'var(--radius-lg)',
                            border: '1px solid var(--color-border)',
                        }}>
                            <div style={{
                                width: 52,
                                height: 52,
                                borderRadius: '50%',
                                background: 'var(--gradient-primary)',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontSize: '1.25rem',
                                fontWeight: 700,
                                color: 'white',
                            }}>
                                {selectedPatient?.name?.charAt(0)}
                            </div>
                            <div style={{ flex: 1 }}>
                                <div style={{ fontWeight: 600, fontSize: '1.0625rem' }}>{selectedPatient?.name}</div>
                                <div style={{ fontSize: '0.8125rem', color: 'var(--color-text-secondary)', marginTop: '0.125rem' }}>
                                    {selectedPatient?.email} · Age: {selectedPatient?.age} · {selectedPatient?.gender}
                                </div>
                                <div style={{ display: 'flex', gap: '0.375rem', marginTop: '0.375rem', flexWrap: 'wrap' }}>
                                    {selectedPatient?.conditions?.map(c => (
                                        <span key={c} className="badge badge-primary" style={{ fontSize: '0.6875rem' }}>{c}</span>
                                    ))}
                                </div>
                            </div>
                            <div style={{ textAlign: 'right' }}>
                                <div style={{
                                    padding: '0.375rem 0.75rem',
                                    borderRadius: 'var(--radius-full)',
                                    fontSize: '0.75rem',
                                    fontWeight: 600,
                                    background: priorityColors[selected.priority]?.bg,
                                    color: priorityColors[selected.priority]?.color,
                                    border: `1px solid ${priorityColors[selected.priority]?.border}`,
                                }}>
                                    {selected.priority?.toUpperCase()} PRIORITY
                                </div>
                                <div style={{ fontSize: '0.75rem', color: 'var(--color-text-tertiary)', marginTop: '0.375rem' }}>
                                    Provider: {selectedPatient?.provider}
                                </div>
                            </div>
                        </div>

                        {/* Original Message */}
                        <div style={{ marginBottom: '1.5rem' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.75rem' }}>
                                <Mail size={16} color="var(--color-primary)" />
                                <h3 style={{ fontSize: '0.9375rem', fontWeight: 600 }}>Patient Message</h3>
                                <span style={{ fontSize: '0.75rem', color: 'var(--color-text-tertiary)', marginLeft: 'auto' }}>
                                    {formatTime(selected.timestamp)}
                                </span>
                            </div>
                            <div style={{
                                padding: '1.25rem',
                                background: 'var(--color-bg-tertiary)',
                                borderRadius: 'var(--radius-md)',
                                border: '1px solid var(--color-border)',
                                fontSize: '0.875rem',
                                lineHeight: 1.7,
                                color: 'var(--color-text-secondary)',
                            }}>
                                <div style={{ fontWeight: 600, color: 'var(--color-text-primary)', marginBottom: '0.5rem' }}>
                                    {selected.subject}
                                </div>
                                {selected.body}
                            </div>
                        </div>

                        {/* AI Classification */}
                        {selected.aiClassification && (
                            <div style={{ marginBottom: '1.5rem' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.75rem' }}>
                                    <Brain size={16} color="var(--color-accent)" />
                                    <h3 style={{ fontSize: '0.9375rem', fontWeight: 600 }}>AI Analysis</h3>
                                </div>
                                <div style={{
                                    display: 'grid',
                                    gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
                                    gap: '0.75rem',
                                }}>
                                    <div style={{
                                        padding: '0.875rem',
                                        background: 'var(--color-bg-card)',
                                        borderRadius: 'var(--radius-md)',
                                        border: '1px solid var(--color-border)',
                                    }}>
                                        <div style={{ fontSize: '0.6875rem', color: 'var(--color-text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.375rem' }}>Intent</div>
                                        <div style={{ fontWeight: 600, fontSize: '0.875rem', textTransform: 'capitalize' }}>
                                            {intentCategories.find(i => i.id === selected.aiClassification.intent)?.label || selected.aiClassification.intent}
                                        </div>
                                    </div>
                                    <div style={{
                                        padding: '0.875rem',
                                        background: 'var(--color-bg-card)',
                                        borderRadius: 'var(--radius-md)',
                                        border: '1px solid var(--color-border)',
                                    }}>
                                        <div style={{ fontSize: '0.6875rem', color: 'var(--color-text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.375rem' }}>Confidence</div>
                                        <div style={{ fontWeight: 600, fontSize: '0.875rem' }}>
                                            {Math.round(selected.aiClassification.confidence * 100)}%
                                        </div>
                                        <div className="progress-bar" style={{ marginTop: '0.375rem' }}>
                                            <div className="progress-bar-fill" style={{ width: `${selected.aiClassification.confidence * 100}%` }} />
                                        </div>
                                    </div>
                                    <div style={{
                                        padding: '0.875rem',
                                        background: 'var(--color-bg-card)',
                                        borderRadius: 'var(--radius-md)',
                                        border: '1px solid var(--color-border)',
                                    }}>
                                        <div style={{ fontSize: '0.6875rem', color: 'var(--color-text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.375rem' }}>Sentiment</div>
                                        <div style={{ fontWeight: 600, fontSize: '0.875rem', textTransform: 'capitalize' }}>
                                            {selected.aiClassification.sentiment}
                                        </div>
                                    </div>
                                    <div style={{
                                        padding: '0.875rem',
                                        background: 'var(--color-bg-card)',
                                        borderRadius: 'var(--radius-md)',
                                        border: '1px solid var(--color-border)',
                                    }}>
                                        <div style={{ fontSize: '0.6875rem', color: 'var(--color-text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.375rem' }}>Urgency</div>
                                        <div style={{
                                            fontWeight: 600,
                                            fontSize: '0.875rem',
                                            textTransform: 'capitalize',
                                            color: priorityColors[selected.aiClassification.urgency]?.color,
                                        }}>
                                            {selected.aiClassification.urgency}
                                        </div>
                                    </div>
                                </div>

                                {/* Extracted Entities */}
                                {selected.aiClassification.entities?.length > 0 && (
                                    <div style={{ marginTop: '0.75rem' }}>
                                        <div style={{ fontSize: '0.75rem', color: 'var(--color-text-tertiary)', marginBottom: '0.375rem' }}>
                                            Extracted Entities:
                                        </div>
                                        <div style={{ display: 'flex', gap: '0.375rem', flexWrap: 'wrap' }}>
                                            {selected.aiClassification.entities.map(entity => (
                                                <span key={entity} className="badge badge-accent" style={{ fontSize: '0.6875rem' }}>
                                                    {entity}
                                                </span>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {/* Context Summary */}
                                {selected.aiClassification.contextSummary && (
                                    <div style={{
                                        marginTop: '0.75rem',
                                        padding: '0.875rem',
                                        background: 'rgba(6,182,212,0.06)',
                                        border: '1px solid rgba(6,182,212,0.15)',
                                        borderRadius: 'var(--radius-md)',
                                        fontSize: '0.8125rem',
                                        color: 'var(--color-text-secondary)',
                                        lineHeight: 1.6,
                                    }}>
                                        <strong style={{ color: 'var(--color-accent)' }}>AI Context Summary: </strong>
                                        {selected.aiClassification.contextSummary}
                                    </div>
                                )}
                            </div>
                        )}

                        {/* AI Draft */}
                        {selected.aiDraft && (
                            <div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.75rem' }}>
                                    <Send size={16} color="var(--color-success)" />
                                    <h3 style={{ fontSize: '0.9375rem', fontWeight: 600 }}>AI-Generated Response Draft</h3>
                                    <span className={`badge badge-${selected.aiDraft.status === 'approved' ? 'success' : selected.aiDraft.status === 'rejected' ? 'danger' : 'warning'}`}>
                                        {selected.aiDraft.status}
                                    </span>
                                </div>
                                <div style={{
                                    padding: '1.25rem',
                                    background: 'rgba(16,185,129,0.04)',
                                    border: '1px solid rgba(16,185,129,0.15)',
                                    borderRadius: 'var(--radius-md)',
                                    fontSize: '0.875rem',
                                    lineHeight: 1.7,
                                    color: 'var(--color-text-secondary)',
                                    whiteSpace: 'pre-line',
                                }}>
                                    {selected.aiDraft.editedContent || selected.aiDraft.content}
                                </div>
                                {selected.aiDraft.knowledgeRefs?.length > 0 && (
                                    <div style={{ marginTop: '0.5rem', fontSize: '0.75rem', color: 'var(--color-text-muted)' }}>
                                        Knowledge references: {selected.aiDraft.knowledgeRefs.join(', ')}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="empty-state" style={{ flex: 1 }}>
                        <Mail size={48} />
                        <p style={{ marginTop: '1rem' }}>Select a message to view details</p>
                    </div>
                )}
            </div>
        </div>
    );
}

import { useState, useMemo, useCallback } from 'react';
import {
    CheckCircle, XCircle, Edit3, Send, Clock, AlertTriangle,
    Eye, ChevronDown, ChevronUp, User, Brain, BookOpen,
    Mail, Globe, MessageCircle, Save, X, RotateCcw
} from 'lucide-react';
import { useApp } from '../context/AppContext';
import { intentCategories, knowledgeBase } from '../data/mockData';

const channelIcons = { email: Mail, portal: Globe, chat: MessageCircle };
const priorityConfig = {
    critical: { bg: 'rgba(239,68,68,0.12)', color: '#f87171', label: 'CRITICAL' },
    high: { bg: 'rgba(245,158,11,0.12)', color: '#fbbf24', label: 'HIGH' },
    medium: { bg: 'rgba(59,130,246,0.12)', color: '#60a5fa', label: 'MEDIUM' },
    low: { bg: 'rgba(16,185,129,0.12)', color: '#34d399', label: 'LOW' },
};

export default function StaffDashboard() {
    const { messages, getPatient, approveDraft, updateDraft, rejectDraft } = useApp();
    const [expandedMsg, setExpandedMsg] = useState(null);
    const [editingMsg, setEditingMsg] = useState(null);
    const [editContent, setEditContent] = useState('');
    const [filterPriority, setFilterPriority] = useState('all');

    const pendingMessages = useMemo(() => {
        return messages
            .filter(m => m.status === 'pending_review' && m.aiDraft)
            .filter(m => filterPriority === 'all' || m.priority === filterPriority)
            .sort((a, b) => {
                const priorityOrder = { critical: 0, high: 1, medium: 2, low: 3 };
                return (priorityOrder[a.priority] || 3) - (priorityOrder[b.priority] || 3);
            });
    }, [messages, filterPriority]);

    const approvedMessages = useMemo(() => {
        return messages.filter(m => m.status === 'approved').slice(0, 5);
    }, [messages]);

    const rejectedMessages = useMemo(() => {
        return messages.filter(m => m.status === 'rejected').slice(0, 5);
    }, [messages]);

    const handleStartEdit = useCallback((msg) => {
        setEditingMsg(msg.id);
        setEditContent(msg.aiDraft.editedContent || msg.aiDraft.content);
    }, []);

    const handleSaveEdit = useCallback((msgId) => {
        updateDraft(msgId, editContent);
        setEditingMsg(null);
        setEditContent('');
    }, [editContent, updateDraft]);

    const handleCancelEdit = useCallback(() => {
        setEditingMsg(null);
        setEditContent('');
    }, []);

    const formatTime = (ts) => {
        const d = new Date(ts);
        return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true }) +
            ' — ' + d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    };

    const stats = useMemo(() => ({
        pending: messages.filter(m => m.status === 'pending_review').length,
        approved: messages.filter(m => m.status === 'approved').length,
        rejected: messages.filter(m => m.status === 'rejected').length,
        critical: messages.filter(m => m.priority === 'critical' && m.status === 'pending_review').length,
    }), [messages]);

    return (
        <div className="page-container">
            <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div>
                    <h1 className="page-title">Staff Dashboard</h1>
                    <p className="page-subtitle">Review, edit, and approve AI-generated response drafts</p>
                </div>
            </div>

            {/* Stats Row */}
            <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(4, 1fr)',
                gap: '1rem',
                marginBottom: '1.5rem',
            }}>
                {[
                    { label: 'Pending Review', value: stats.pending, color: '#f59e0b', icon: Clock },
                    { label: 'Critical', value: stats.critical, color: '#ef4444', icon: AlertTriangle },
                    { label: 'Approved', value: stats.approved, color: '#10b981', icon: CheckCircle },
                    { label: 'Rejected', value: stats.rejected, color: '#6366f1', icon: XCircle },
                ].map(stat => (
                    <div
                        key={stat.label}
                        className="card-flat"
                        style={{
                            padding: '1.25rem',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '1rem',
                        }}
                    >
                        <div style={{
                            width: 44,
                            height: 44,
                            borderRadius: 'var(--radius-md)',
                            background: `${stat.color}15`,
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                        }}>
                            <stat.icon size={22} color={stat.color} />
                        </div>
                        <div>
                            <div style={{ fontSize: '1.5rem', fontWeight: 800, lineHeight: 1 }}>{stat.value}</div>
                            <div style={{ fontSize: '0.8125rem', color: 'var(--color-text-secondary)', marginTop: '0.125rem' }}>{stat.label}</div>
                        </div>
                    </div>
                ))}
            </div>

            {/* Filter Bar */}
            <div style={{
                display: 'flex',
                gap: '0.5rem',
                marginBottom: '1.25rem',
                alignItems: 'center',
            }}>
                <span style={{ fontSize: '0.8125rem', color: 'var(--color-text-secondary)', marginRight: '0.5rem' }}>Filter:</span>
                {['all', 'critical', 'high', 'medium', 'low'].map(p => (
                    <button
                        key={p}
                        className={`btn btn-sm ${filterPriority === p ? 'btn-primary' : 'btn-secondary'}`}
                        onClick={() => setFilterPriority(p)}
                        style={{ textTransform: 'capitalize', fontSize: '0.75rem' }}
                    >
                        {p === 'all' ? 'All' : p}
                    </button>
                ))}
            </div>

            {/* Pending Review Queue */}
            <div style={{ marginBottom: '2rem' }}>
                <h2 className="section-title" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <Clock size={18} color="var(--color-warning)" />
                    Pending Review Queue ({pendingMessages.length})
                </h2>

                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                    {pendingMessages.map(msg => {
                        const patient = getPatient(msg.patientId);
                        const pConfig = priorityConfig[msg.priority] || priorityConfig.medium;
                        const isExpanded = expandedMsg === msg.id;
                        const isEditing = editingMsg === msg.id;
                        const ChannelIcon = channelIcons[msg.channel] || MessageCircle;
                        const intentInfo = intentCategories.find(i => i.id === msg.aiClassification?.intent);
                        const refs = msg.aiDraft?.knowledgeRefs || [];
                        const kbRefs = knowledgeBase.filter(kb => refs.includes(kb.id));

                        return (
                            <div
                                key={msg.id}
                                id={`review-${msg.id}`}
                                className="card-flat"
                                style={{
                                    padding: 0,
                                    overflow: 'hidden',
                                    borderLeft: `4px solid ${pConfig.color}`,
                                }}
                            >
                                {/* Message Header */}
                                <div
                                    style={{
                                        padding: '1rem 1.5rem',
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '1rem',
                                        cursor: 'pointer',
                                    }}
                                    onClick={() => setExpandedMsg(isExpanded ? null : msg.id)}
                                >
                                    <div style={{
                                        width: 44,
                                        height: 44,
                                        borderRadius: '50%',
                                        background: 'var(--gradient-primary)',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center',
                                        fontSize: '1rem',
                                        fontWeight: 700,
                                        color: 'white',
                                        flexShrink: 0,
                                    }}>
                                        {patient?.name?.charAt(0)}
                                    </div>
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                            <span style={{ fontWeight: 600, fontSize: '0.9375rem' }}>{patient?.name}</span>
                                            <span className="badge" style={{ background: pConfig.bg, color: pConfig.color, fontSize: '0.625rem' }}>
                                                {pConfig.label}
                                            </span>
                                            {intentInfo && (
                                                <span className="badge badge-accent" style={{ fontSize: '0.625rem' }}>
                                                    {intentInfo.label}
                                                </span>
                                            )}
                                        </div>
                                        <div style={{ fontSize: '0.8125rem', color: 'var(--color-text-secondary)', marginTop: '0.125rem' }}>
                                            {msg.subject}
                                        </div>
                                    </div>

                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', flexShrink: 0 }}>
                                        <span style={{ display: 'flex', alignItems: 'center', gap: '0.25rem', fontSize: '0.75rem', color: 'var(--color-text-tertiary)' }}>
                                            <ChannelIcon size={14} /> {msg.channel}
                                        </span>
                                        <span style={{ fontSize: '0.75rem', color: 'var(--color-text-muted)' }}>
                                            {formatTime(msg.timestamp)}
                                        </span>
                                        {isExpanded ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                                    </div>
                                </div>

                                {/* Expanded Content */}
                                {isExpanded && (
                                    <div className="animate-fade-in" style={{ padding: '0 1.5rem 1.5rem' }}>
                                        {/* Original Message */}
                                        <div style={{
                                            padding: '1rem',
                                            background: 'var(--color-bg-tertiary)',
                                            borderRadius: 'var(--radius-md)',
                                            marginBottom: '1rem',
                                            borderLeft: '3px solid var(--color-primary)',
                                        }}>
                                            <div style={{ fontSize: '0.6875rem', fontWeight: 600, color: 'var(--color-text-tertiary)', textTransform: 'uppercase', marginBottom: '0.5rem' }}>
                                                Original Patient Message
                                            </div>
                                            <div style={{ fontSize: '0.875rem', color: 'var(--color-text-secondary)', lineHeight: 1.6 }}>
                                                {msg.body}
                                            </div>
                                        </div>

                                        {/* AI Classification Summary */}
                                        {msg.aiClassification && (
                                            <div style={{
                                                display: 'flex',
                                                gap: '1rem',
                                                marginBottom: '1rem',
                                                flexWrap: 'wrap',
                                            }}>
                                                <div style={{
                                                    padding: '0.625rem 1rem',
                                                    background: 'rgba(6,182,212,0.06)',
                                                    borderRadius: 'var(--radius-md)',
                                                    display: 'flex',
                                                    alignItems: 'center',
                                                    gap: '0.5rem',
                                                }}>
                                                    <Brain size={14} color="var(--color-accent)" />
                                                    <span style={{ fontSize: '0.75rem', color: 'var(--color-text-secondary)' }}>
                                                        Confidence: <strong style={{ color: 'var(--color-accent-light)' }}>{Math.round(msg.aiClassification.confidence * 100)}%</strong>
                                                    </span>
                                                </div>
                                                <div style={{
                                                    padding: '0.625rem 1rem',
                                                    background: 'rgba(99,102,241,0.06)',
                                                    borderRadius: 'var(--radius-md)',
                                                    display: 'flex',
                                                    alignItems: 'center',
                                                    gap: '0.5rem',
                                                }}>
                                                    <span style={{ fontSize: '0.75rem', color: 'var(--color-text-secondary)' }}>
                                                        Sentiment: <strong>{msg.aiClassification.sentiment}</strong>
                                                    </span>
                                                </div>
                                                {msg.aiClassification.entities?.length > 0 && (
                                                    <div style={{ display: 'flex', gap: '0.25rem', alignItems: 'center', flexWrap: 'wrap' }}>
                                                        {msg.aiClassification.entities.slice(0, 5).map(e => (
                                                            <span key={e} className="badge badge-primary" style={{ fontSize: '0.625rem' }}>{e}</span>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                        )}

                                        {/* Knowledge Base References */}
                                        {kbRefs.length > 0 && (
                                            <div style={{ marginBottom: '1rem' }}>
                                                <div style={{ fontSize: '0.6875rem', fontWeight: 600, color: 'var(--color-text-tertiary)', textTransform: 'uppercase', marginBottom: '0.5rem', display: 'flex', alignItems: 'center', gap: '0.375rem' }}>
                                                    <BookOpen size={12} /> Knowledge Base References
                                                </div>
                                                <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                                                    {kbRefs.map(kb => (
                                                        <div key={kb.id} style={{
                                                            padding: '0.5rem 0.75rem',
                                                            background: 'var(--color-bg-tertiary)',
                                                            borderRadius: 'var(--radius-sm)',
                                                            border: '1px solid var(--color-border)',
                                                            fontSize: '0.75rem',
                                                        }}>
                                                            <span style={{ color: 'var(--color-primary-light)', fontWeight: 500 }}>{kb.id}</span>
                                                            <span style={{ color: 'var(--color-text-tertiary)' }}> — {kb.title}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        )}

                                        {/* AI Draft Response */}
                                        <div style={{
                                            borderRadius: 'var(--radius-md)',
                                            border: '1px solid rgba(16,185,129,0.2)',
                                            overflow: 'hidden',
                                            marginBottom: '1rem',
                                        }}>
                                            <div style={{
                                                padding: '0.75rem 1rem',
                                                background: 'rgba(16,185,129,0.08)',
                                                display: 'flex',
                                                alignItems: 'center',
                                                gap: '0.5rem',
                                                borderBottom: '1px solid rgba(16,185,129,0.15)',
                                            }}>
                                                <Sparkle size={14} color="var(--color-success)" />
                                                <span style={{ fontSize: '0.8125rem', fontWeight: 600, color: 'var(--color-success-light)' }}>
                                                    AI-Generated Response Draft
                                                </span>
                                                {msg.aiDraft.status === 'edited' && (
                                                    <span className="badge badge-info" style={{ fontSize: '0.625rem', marginLeft: 'auto' }}>Edited</span>
                                                )}
                                            </div>
                                            <div style={{ padding: '1rem' }}>
                                                {isEditing ? (
                                                    <textarea
                                                        className="input"
                                                        value={editContent}
                                                        onChange={e => setEditContent(e.target.value)}
                                                        style={{
                                                            minHeight: '250px',
                                                            fontFamily: 'var(--font-sans)',
                                                            lineHeight: 1.6,
                                                            fontSize: '0.875rem',
                                                        }}
                                                    />
                                                ) : (
                                                    <div style={{
                                                        fontSize: '0.875rem',
                                                        lineHeight: 1.7,
                                                        color: 'var(--color-text-secondary)',
                                                        whiteSpace: 'pre-line',
                                                    }}>
                                                        {msg.aiDraft.editedContent || msg.aiDraft.content}
                                                    </div>
                                                )}
                                            </div>
                                        </div>

                                        {/* Action Buttons */}
                                        <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'flex-end' }}>
                                            {isEditing ? (
                                                <>
                                                    <button className="btn btn-secondary" onClick={handleCancelEdit}>
                                                        <X size={16} /> Cancel
                                                    </button>
                                                    <button className="btn btn-primary" onClick={() => handleSaveEdit(msg.id)}>
                                                        <Save size={16} /> Save Changes
                                                    </button>
                                                </>
                                            ) : (
                                                <>
                                                    <button className="btn btn-danger btn-sm" onClick={() => rejectDraft(msg.id)}>
                                                        <XCircle size={16} /> Reject
                                                    </button>
                                                    <button className="btn btn-secondary btn-sm" onClick={() => handleStartEdit(msg)}>
                                                        <Edit3 size={16} /> Edit Draft
                                                    </button>
                                                    <button className="btn btn-success" onClick={() => approveDraft(msg.id)}>
                                                        <CheckCircle size={16} /> Approve & Send
                                                    </button>
                                                </>
                                            )}
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}

                    {pendingMessages.length === 0 && (
                        <div className="empty-state" style={{ padding: '3rem' }}>
                            <CheckCircle size={48} color="var(--color-success)" />
                            <p style={{ marginTop: '1rem', fontSize: '1rem', fontWeight: 500 }}>All caught up!</p>
                            <p style={{ fontSize: '0.875rem', color: 'var(--color-text-tertiary)' }}>No messages pending review.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Recently Approved */}
            {approvedMessages.length > 0 && (
                <div>
                    <h2 className="section-title" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <CheckCircle size={18} color="var(--color-success)" />
                        Recently Approved ({approvedMessages.length})
                    </h2>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                        {approvedMessages.map(msg => {
                            const patient = getPatient(msg.patientId);
                            const ChannelIcon = channelIcons[msg.channel] || MessageCircle;
                            return (
                                <div
                                    key={msg.id}
                                    style={{
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '1rem',
                                        padding: '0.875rem 1.25rem',
                                        background: 'var(--color-bg-card)',
                                        borderRadius: 'var(--radius-md)',
                                        border: '1px solid var(--color-border-light)',
                                        opacity: 0.7,
                                    }}
                                >
                                    <CheckCircle size={18} color="var(--color-success)" />
                                    <div style={{ flex: 1 }}>
                                        <span style={{ fontWeight: 500, fontSize: '0.875rem' }}>{patient?.name}</span>
                                        <span style={{ color: 'var(--color-text-tertiary)', fontSize: '0.8125rem' }}> — {msg.subject}</span>
                                    </div>
                                    <span className="badge badge-success" style={{ fontSize: '0.625rem' }}>Sent</span>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}
        </div>
    );
}

// Small helper component
function Sparkle(props) {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width={props.size || 24} height={props.size || 24} viewBox="0 0 24 24" fill="none" stroke={props.color || 'currentColor'} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M12 3l1.912 5.813a2 2 0 0 0 1.275 1.275L21 12l-5.813 1.912a2 2 0 0 0-1.275 1.275L12 21l-1.912-5.813a2 2 0 0 0-1.275-1.275L3 12l5.813-1.912a2 2 0 0 0 1.275-1.275L12 3z" />
        </svg>
    );
}

